'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { TrendingUp, Users, Tags, HardDrive, Activity } from 'lucide-react';

interface AnalyticsData {
    uploadsByDay: Array<{ date: string; count: number }>;
    topUploaders: Array<{ email: string; name: string; clipCount: number }>;
    popularTags: Array<{ tag: string; count: number }>;
    storageByUser: Array<{ email: string; totalSize: number }>;
    recentActions: Array<{ action: string; adminEmail: string; details: string; timestamp: number }>;
}

export default function AnalyticsPage() {
    const [data, setData] = useState<AnalyticsData | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetch('/api/admin/analytics')
            .then((res) => res.json())
            .then((data) => {
                setData(data);
                setLoading(false);
            })
            .catch((err) => {
                console.error('Failed to load analytics:', err);
                setLoading(false);
            });
    }, []);

    if (loading || !data) {
        return <div>Loading...</div>;
    }

    const formatBytes = (bytes: number) => {
        if (bytes === 0) return '0 B';
        const k = 1024;
        const sizes = ['B', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return Math.round(bytes / Math.pow(k, i) * 100) / 100 + ' ' + sizes[i];
    };

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold tracking-tight">Analytics & Logs</h1>
                <p className="text-muted-foreground">Platform insights and activity</p>
            </div>

            <div className="grid gap-6 md:grid-cols-2">
                {/* Top Uploaders */}
                <Card className="border-white/10 bg-black/40 backdrop-blur-lg">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Users className="h-5 w-5 text-primary" />
                            Top Uploaders
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-2">
                            {data.topUploaders.map((user, index) => (
                                <div
                                    key={user.email}
                                    className="flex items-center justify-between rounded-lg border border-white/10 bg-black/20 p-3"
                                >
                                    <div>
                                        <p className="font-medium">{user.email}</p>
                                        <p className="text-xs text-muted-foreground">{user.name || 'No name'}</p>
                                    </div>
                                    <Badge>{user.clipCount} clips</Badge>
                                </div>
                            ))}
                            {data.topUploaders.length === 0 && (
                                <p className="text-center text-sm text-muted-foreground">No data</p>
                            )}
                        </div>
                    </CardContent>
                </Card>

                {/* Popular Tags */}
                <Card className="border-white/10 bg-black/40 backdrop-blur-lg">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Tags className="h-5 w-5 text-primary" />
                            Popular Tags
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="flex flex-wrap gap-2">
                            {data.popularTags.map((tag) => (
                                <Badge key={tag.tag} variant="secondary" className="text-sm">
                                    {tag.tag} ({tag.count})
                                </Badge>
                            ))}
                            {data.popularTags.length === 0 && (
                                <p className="text-sm text-muted-foreground">No tags</p>
                            )}
                        </div>
                    </CardContent>
                </Card>

                {/* Storage by User */}
                <Card className="border-white/10 bg-black/40 backdrop-blur-lg">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <HardDrive className="h-5 w-5 text-primary" />
                            Storage by User
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-2">
                            {data.storageByUser.map((user) => (
                                <div
                                    key={user.email}
                                    className="flex items-center justify-between rounded-lg border border-white/10 bg-black/20 p-3"
                                >
                                    <p className="font-medium">{user.email}</p>
                                    <Badge>{formatBytes(user.totalSize)}</Badge>
                                </div>
                            ))}
                            {data.storageByUser.length === 0 && (
                                <p className="text-center text-sm text-muted-foreground">No data</p>
                            )}
                        </div>
                    </CardContent>
                </Card>

                {/* Recent Admin Actions */}
                <Card className="border-white/10 bg-black/40 backdrop-blur-lg">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Activity className="h-5 w-5 text-primary" />
                            Recent Admin Actions
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-2">
                            {data.recentActions.slice(0, 10).map((action, index) => (
                                <div
                                    key={index}
                                    className="rounded-lg border border-white/10 bg-black/20 p-3"
                                >
                                    <div className="flex items-center justify-between">
                                        <p className="text-sm font-medium">{action.action}</p>
                                        <p className="text-xs text-muted-foreground">
                                            {new Date(action.timestamp * 1000).toLocaleString()}
                                        </p>
                                    </div>
                                    <p className="text-xs text-muted-foreground">
                                        by {action.adminEmail} ÔÇó {action.details}
                                    </p>
                                </div>
                            ))}
                            {data.recentActions.length === 0 && (
                                <p className="text-center text-sm text-muted-foreground">No actions yet</p>
                            )}
                        </div>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Checkbox } from '@/components/ui/checkbox';
import { Search, Trash2, Star, StarOff } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import Image from 'next/image';

interface Clip {
    id: string;
    title: string;
    thumbnailUrl: string;
    fileUrl: string;
    tags: string;
    featured: number;
    uploadDate: number;
    userId: string;
}

export default function ClipsPage() {
    const [clips, setClips] = useState<Clip[]>([]);
    const [search, setSearch] = useState('');
    const [selectedClips, setSelectedClips] = useState<Set<string>>(new Set());
    const [loading, setLoading] = useState(true);
    const { toast } = useToast();

    const fetchClips = async () => {
        setLoading(true);
        const res = await fetch('/api/clips');
        const data = await res.json();
        setClips(data);
        setLoading(false);
    };

    useEffect(() => {
        fetchClips();
    }, []);

    const filteredClips = clips.filter((clip) => {
        if (!search) return true;
        const searchLower = search.toLowerCase();
        return (
            clip.title.toLowerCase().includes(searchLower) ||
            clip.tags.toLowerCase().includes(searchLower)
        );
    });

    const handleToggleSelect = (clipId: string) => {
        const newSelected = new Set(selectedClips);
        if (newSelected.has(clipId)) {
            newSelected.delete(clipId);
        } else {
            newSelected.add(clipId);
        }
        setSelectedClips(newSelected);
    };

    const handleSelectAll = () => {
        if (selectedClips.size === filteredClips.length) {
            setSelectedClips(new Set());
        } else {
            setSelectedClips(new Set(filteredClips.map((c) => c.id)));
        }
    };

    const handleBulkDelete = async () => {
        if (selectedClips.size === 0) return;
        if (!window.confirm(`Delete ${selectedClips.size} clips?`)) return;

        try {
            const res = await fetch('/api/admin/clips/bulk-delete', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ clipIds: Array.from(selectedClips) }),
            });

            if (!res.ok) throw new Error('Failed to delete clips');

            toast({
                title: 'Clips Deleted',
                description: `${selectedClips.size} clips removed successfully.`,
            });

            setSelectedClips(new Set());
            fetchClips();
        } catch (error) {
            toast({
                variant: 'destructive',
                title: 'Error',
                description: 'Failed to delete clips.',
            });
        }
    };

    const handleToggleFeature = async (clipId: string, currentFeatured: number) => {
        try {
            const newFeatured = currentFeatured ? 0 : 1;
            const res = await fetch(`/api/admin/clips/${clipId}/feature`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ featured: newFeatured }),
            });

            if (!res.ok) throw new Error('Failed to feature clip');

            toast({
                title: newFeatured ? 'Clip Featured' : 'Clip Unfeatured',
            });

            fetchClips();
        } catch (error) {
            toast({
                variant: 'destructive',
                title: 'Error',
                description: 'Failed to update featured status.',
            });
        }
    };

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold tracking-tight">Clip Management</h1>
                <p className="text-muted-foreground">Manage, feature, and moderate clips</p>
            </div>

            {/* Search & Actions */}
            <div className="flex gap-4">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                    <Input
                        placeholder="Search by title or tags..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="pl-10"
                    />
                </div>
                {selectedClips.size > 0 && (
                    <Button variant="destructive" onClick={handleBulkDelete}>
                        <Trash2 className="mr-2 h-4 w-4" />
                        Delete {selectedClips.size} clips
                    </Button>
                )}
            </div>

            {/* Clip List */}
            <Card className="border-white/10 bg-black/40 backdrop-blur-lg">
                <CardHeader>
                    <div className="flex items-center justify-between">
                        <CardTitle>All Clips ({filteredClips.length})</CardTitle>
                        <Button variant="ghost" size="sm" onClick={handleSelectAll}>
                            {selectedClips.size === filteredClips.length ? 'Deselect All' : 'Select All'}
                        </Button>
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="grid gap-4 md:grid-cols-2">
                        {filteredClips.map((clip) => {
                            const tags = clip.tags.split(',').filter(Boolean);
                            return (
                                <div
                                    key={clip.id}
                                    className="flex gap-4 rounded-lg border border-white/10 bg-black/20 p-3"
                                >
                                    <Checkbox
                                        checked={selectedClips.has(clip.id)}
                                        onCheckedChange={() => handleToggleSelect(clip.id)}
                                    />

                                    <div className="relative h-24 w-32 flex-shrink-0 overflow-hidden rounded">
                                        <Image
                                            src={clip.thumbnailUrl}
                                            alt={clip.title}
                                            fill
                                            className="object-cover"
                                        />
                                    </div>

                                    <div className="flex-1">
                                        <div className="flex items-start justify-between">
                                            <div className="flex-1">
                                                <p className="font-medium">{clip.title}</p>
                                                <div className="mt-1 flex flex-wrap gap-1">
                                                    {tags.map((tag) => (
                                                        <Badge key={tag} variant="secondary" className="text-xs">
                                                            {tag.trim()}
                                                        </Badge>
                                                    ))}
                                                </div>
                                                <p className="mt-1 text-xs text-muted-foreground">
                                                    {new Date(clip.uploadDate * 1000).toLocaleDateString()}
                                                </p>
                                            </div>

                                            <Button
                                                variant={clip.featured ? 'default' : 'outline'}
                                                size="sm"
                                                onClick={() => handleToggleFeature(clip.id, clip.featured)}
                                            >
                                                {clip.featured ? (
                                                    <Star className="h-4 w-4 fill-current" />
                                                ) : (
                                                    <StarOff className="h-4 w-4" />
                                                )}
                                            </Button>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}

                        {filteredClips.length === 0 && !loading && (
                            <p className="col-span-2 text-center text-muted-foreground">No clips found</p>
                        )}
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { Search, Trash2, Ban, Shield, UserCog } from 'lucide-react';
import { useToast } from '@/hooks/use-toast';

interface User {
    id: string;
    email: string;
    name: string | null;
    role: string;
    banned: number;
    createdAt: number;
}

export default function UsersPage() {
    const [users, setUsers] = useState<User[]>([]);
    const [search, setSearch] = useState('');
    const [roleFilter, setRoleFilter] = useState('');
    const [loading, setLoading] = useState(true);
    const { toast } = useToast();

    const fetchUsers = async () => {
        setLoading(true);
        const params = new URLSearchParams();
        if (search) params.set('search', search);
        if (roleFilter) params.set('role', roleFilter);

        const res = await fetch(`/api/admin/users?${params}`);
        const data = await res.json();
        setUsers(data);
        setLoading(false);
    };

    useEffect(() => {
        fetchUsers();
    }, [search, roleFilter]);

    const handleBan = async (userId: string, currentBanned: number) => {
        try {
            const newBanned = currentBanned ? 0 : 1;
            const res = await fetch(`/api/admin/users/${userId}/ban`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ banned: newBanned }),
            });

            if (!res.ok) throw new Error('Failed to update ban status');

            toast({
                title: newBanned ? 'User Banned' : 'User Unbanned',
                description: `User has been ${newBanned ? 'banned' : 'unbanned'} successfully.`,
            });

            fetchUsers();
        } catch (error) {
            toast({
                variant: 'destructive',
                title: 'Error',
                description: 'Failed to update ban status.',
            });
        }
    };

    const handleChangeRole = async (userId: string, newRole: string) => {
        try {
            const res = await fetch(`/api/admin/users/${userId}/role`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ role: newRole }),
            });

            if (!res.ok) throw new Error('Failed to change role');

            toast({
                title: 'Role Changed',
                description: `User role updated to ${newRole}.`,
            });

            fetchUsers();
        } catch (error) {
            toast({
                variant: 'destructive',
                title: 'Error',
                description: 'Failed to change role.',
            });
        }
    };

    const handleDelete = async (userId: string, email: string) => {
        if (!window.confirm(`Delete user ${email}? This will also delete all their clips.`)) return;

        try {
            const res = await fetch('/api/admin/users', {
                method: 'DELETE',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ userId }),
            });

            if (!res.ok) throw new Error('Failed to delete user');

            toast({
                title: 'User Deleted',
                description: 'User and all their clips have been removed.',
            });

            fetchUsers();
        } catch (error) {
            toast({
                variant: 'destructive',
                title: 'Error',
                description: 'Failed to delete user.',
            });
        }
    };

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-3xl font-bold tracking-tight">User Management</h1>
                <p className="text-muted-foreground">Manage users, roles, and permissions</p>
            </div>

            {/* Filters */}
            <div className="flex gap-4">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                    <Input
                        placeholder="Search by email or name..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="pl-10"
                    />
                </div>
                <Select value={roleFilter} onValueChange={setRoleFilter}>
                    <SelectTrigger className="w-48">
                        <SelectValue placeholder="Filter by role" />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="">All Roles</SelectItem>
                        <SelectItem value="USER">User</SelectItem>
                        <SelectItem value="ADMIN">Admin</SelectItem>
                    </SelectContent>
                </Select>
            </div>

            {/* User List */}
            <Card className="border-white/10 bg-black/40 backdrop-blur-lg">
                <CardHeader>
                    <CardTitle>All Users ({users.length})</CardTitle>
                </CardHeader>
                <CardContent>
                    <div className="space-y-3">
                        {users.map((user) => (
                            <div
                                key={user.id}
                                className="flex items-center gap-4 rounded-lg border border-white/10 bg-black/20 p-4"
                            >
                                <div className="flex-1">
                                    <div className="flex items-center gap-2">
                                        <p className="font-medium">{user.email}</p>
                                        {user.banned === 1 && (
                                            <Badge variant="destructive" className="text-xs">
                                                BANNED
                                            </Badge>
                                        )}
                                    </div>
                                    <p className="text-sm text-muted-foreground">
                                        {user.name || 'No name'} ÔÇó Joined {new Date(user.createdAt * 1000).toLocaleDateString()}
                                    </p>
                                </div>

                                <div className="flex items-center gap-2">
                                    <Select
                                        value={user.role}
                                        onValueChange={(role) => handleChangeRole(user.id, role)}
                                    >
                                        <SelectTrigger className="w-32">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="USER">User</SelectItem>
                                            <SelectItem value="ADMIN">Admin</SelectItem>
                                        </SelectContent>
                                    </Select>

                                    <Button
                                        variant={user.banned ? 'outline' : 'destructive'}
                                        size="sm"
                                        onClick={() => handleBan(user.id, user.banned)}
                                    >
                                        <Ban className="h-4 w-4" />
                                    </Button>

                                    <Button
                                        variant="destructive"
                                        size="sm"
                                        onClick={() => handleDelete(user.id, user.email)}
                                    >
                                        <Trash2 className="h-4 w-4" />
                                    </Button>
                                </div>
                            </div>
                        ))}

                        {users.length === 0 && !loading && (
                            <p className="text-center text-muted-foreground">No users found</p>
                        )}
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

import prisma from "@/lib/prisma";
import { NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { del } from "@vercel/blob";
import { bufferToDataUri } from "@/lib/storage";
import type { SessionUser } from '@/types/session';

// GET - Fetch a single clip with uploader info
export async function GET(
    req: Request,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const { id: clipId } = await params;

        const clip = await prisma.clip.findUnique({
            where: { id: clipId },
            include: {
                user: {
                    select: {
                        id: true,
                        email: true,
                        displayName: true,
                        name: true,
                        profilePicture: true,
                        profilePictureData: true
                    }
                }
            }
        });

        if (!clip) {
            return new NextResponse("Not Found", { status: 404 });
        }

        // Convert clip binary to Data URI
        const processedClip: any = { ...clip };
        if (processedClip.thumbnailData) {
            processedClip.thumbnailUrl = bufferToDataUri(processedClip.thumbnailData, 'image/png');
        }

        // Use the custom video endpoint if we have data in DB
        if (processedClip.fileData) {
            processedClip.fileUrl = `/api/clips/${clipId}/video`;
        }

        // Cleanup response
        delete processedClip.thumbnailData;
        delete processedClip.fileData;

        // Process uploader data
        if (processedClip.user) {
            if (processedClip.user.profilePictureData) {
                processedClip.user.profilePicture = bufferToDataUri(processedClip.user.profilePictureData, 'image/png');
            }
            delete processedClip.user.profilePictureData;
        }

        return NextResponse.json({
            clip: {
                ...processedClip,
                uploader: processedClip.user ? processedClip.user : null
            }
        });

    } catch (error) {
        console.error("Error fetching clip:", error);
        return new NextResponse("Internal Error", { status: 500 });
    }
}

export async function DELETE(
    req: Request,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const session = await auth();

        if (!session) {
            return new NextResponse("Unauthorized", { status: 401 });
        }

        const { id: clipId } = await params;

        // Get clip info
        const clip = await prisma.clip.findUnique({
            where: { id: clipId }
        });

        if (!clip) {
            return new NextResponse("Not Found", { status: 404 });
        }

        // Check permissions: Admin can delete any clip, users can only delete their own
        const userRole = (session.user as SessionUser)?.role;
        const userId = (session.user as SessionUser)?.id;

        const isAdmin = userRole === "ADMIN";
        const isOwner = clip.userId === userId;

        if (!isAdmin && !isOwner) {
            return new NextResponse("Forbidden: You can only delete your own clips", { status: 403 });
        }

        // Delete from Vercel Blob storage
        try {
            if (clip.fileUrl && clip.fileUrl.includes('vercel-storage.com')) {
                await del(clip.fileUrl, { token: process.env.BLOB_READ_WRITE_TOKEN });
            }

            if (clip.thumbnailUrl && clip.thumbnailUrl.includes('vercel-storage.com')) {
                await del(clip.thumbnailUrl, { token: process.env.BLOB_READ_WRITE_TOKEN });
            }
        } catch (err) {
            console.warn("Could not delete from Vercel Blob:", err);
        }

        // Delete from database
        await prisma.clip.delete({
            where: { id: clipId }
        });

        return NextResponse.json({ success: true });
    } catch (error) {
        console.error("Error deleting clip:", error);
        return new NextResponse("Internal Error", { status: 500 });
    }
}

import prisma from "@/lib/prisma";
import { NextResponse } from "next/server";
import { bufferToDataUri } from "@/lib/storage";

export async function GET() {
    try {
        const clips = await prisma.clip.findMany({
            orderBy: {
                uploadDate: 'desc'
            }
        });

        const processedClips = clips.map((clip: any) => {
            const processed = { ...clip };
            if (processed.thumbnailData) {
                processed.thumbnailUrl = bufferToDataUri(processed.thumbnailData, 'image/png');
            }
            // Do not send binary video data in the list view
            delete processed.thumbnailData;
            delete processed.fileData;
            return processed;
        });

        return NextResponse.json(processedClips);
    } catch (error) {
        console.error("Error fetching clips:", error);
        return new NextResponse("Internal Error", { status: 500 });
    }
}

import prisma from '@/lib/prisma';
import { NextResponse } from 'next/server';
import { bufferToDataUri } from '@/lib/storage';

// GET - Fetch user profile and their clips
export async function GET(
    req: Request,
    { params }: { params: Promise<{ userId: string }> }
) {
    try {
        const { userId } = await params;

        // Check for hardcoded admin
        let user: any;
        if (userId === 'admin') {
            user = await prisma.user.findUnique({
                where: { id: 'admin' }
            });

            if (!user) {
                user = {
                    id: 'admin',
                    email: 'admin@example.com',
                    name: 'Administrator',
                    displayName: 'Site Admin',
                    role: 'ADMIN',
                    createdAt: new Date(),
                };
            }
        } else {
            user = await prisma.user.findUnique({
                where: { id: userId }
            });
        }

        if (!user) {
            return new NextResponse('User not found', { status: 404 });
        }

        // Convert binary images to Data URIs (simple detection for common types)
        if (user.profilePictureData) {
            user.profilePicture = bufferToDataUri(user.profilePictureData, 'image/png');
            delete user.profilePictureData;
        }
        if (user.bannerImageData) {
            user.bannerImage = bufferToDataUri(user.bannerImageData, 'image/png');
            delete user.bannerImageData;
        }

        // Get user's clips
        const clips = await prisma.clip.findMany({
            where: { userId },
            orderBy: { uploadDate: 'desc' }
        });

        const clipsWithDataUris = clips.map((clip: any) => {
            const clipData = { ...clip };
            if (clipData.thumbnailData) {
                clipData.thumbnailUrl = bufferToDataUri(clipData.thumbnailData, 'image/png');
                delete clipData.thumbnailData;
            }
            // Note: We don't convert the full video to data URI here as it would be too large for a JSON response
            // Usually, you'd serve the video from a separate GET route that streams the Buffer.
            delete clipData.fileData;
            return clipData;
        });

        // Get upload count
        const stats = {
            totalUploads: clips.length,
            joinDate: user.createdAt,
        };

        return NextResponse.json({
            user,
            clips: clipsWithDataUris,
            stats,
        });

    } catch (error) {
        console.error('Error fetching user profile:', error);
        return new NextResponse('Internal Error', { status: 500 });
    }
}

